style.t:
:root {
  --t-primary:        #DC143C;
  --t-header-bg:      linear-gradient(135deg,#0a0a0a,#2a0a10);
  --t-header-text:    #f5f5f5;
  --t-drawer-bg:      #1e1e1e;
  --t-border-w:       3px;
  --t-shadow-c:       rgba(220,20,60,0.3);
  --t-tab-bg:         linear-gradient(180deg,#5a0010,#8B0000);
  --t-arrow-c:        #f5a0a0;
  --t-overlay:        rgba(0,0,0,0.75);
  --t-card-bg:        rgba(30,5,10,0.95);
  --t-card-text:      #f5f5f5;
  --t-cancel-bg:      rgba(220,20,60,0.15);
  --t-cancel-border:  rgba(220,20,60,0.3);
  --t-cancel-text:    #f5f5f5;
  --t-confirm-bg:     #DC143C;
  --t-confirm-text:   #fff;
}

:root {
  --t-primary:        #F5C842;
  --t-header-bg:      linear-gradient(135deg,#0d0d1f,#1a1400);
  --t-header-text:    #F5C842;
  --t-drawer-bg:      rgba(9,9,18,0.99);
  --t-border-w:       3px;
  --t-shadow-c:       rgba(245,200,66,0.2);
  --t-tab-bg:         linear-gradient(135deg,#F5C842 0%,#FF9F1C 100%);
  --t-arrow-c:        #F5C842;
  --t-overlay:        rgba(0,0,0,0.85);
  --t-card-bg:        #090912;
  --t-card-text:      rgba(255,255,255,0.9);
  --t-cancel-bg:      rgba(255,255,255,0.06);
  --t-cancel-border:  rgba(245,200,66,0.3);
  --t-cancel-text:    rgba(255,255,255,0.8);
  --t-confirm-bg:     linear-gradient(135deg,#F5C842,#FF9F1C);
  --t-confirm-text:   #090912;
}

template.script:
//
  (function() {

    /* Read theme colours injected as data-attributes */
    var _wrap = document.querySelector('.player-modal-content');
    var UNSOLD_COLOR = _wrap ? (_wrap.getAttribute('data-unsold-color') || '#b71c1c') : '#b71c1c';
    var UNSOLD_TEXT  = _wrap ? (_wrap.getAttribute('data-unsold-text')  || '#fff')    : '#fff';

    /* ── changeImage: in drawer context close + reload grid;
          fallback to full-page reload (for standalone template pages)  ── */
    window.changeImage = function() {
      if (window.closePlayerDrawer) {
        closePlayerDrawer();
        if (window._auctionReloadGrid) window._auctionReloadGrid();
      } else {
        window.location.reload();
      }
    };

    /* ── Unsold confirm modal ──────────────────────────────────────── */
    window.setPlayerUnsold = function() {
      var modal = document.getElementById('unsoldConfirmModal');
      if (modal) modal.style.display = 'flex';
    };

    var _cancelBtn  = document.getElementById('unsoldModalCancel');
    var _confirmBtn = document.getElementById('unsoldModalConfirm');

    if (_cancelBtn) {
      _cancelBtn.addEventListener('click', function() {
        document.getElementById('unsoldConfirmModal').style.display = 'none';
      });
    }

    if (_confirmBtn) {
      _confirmBtn.addEventListener('click', function() {
        document.getElementById('unsoldConfirmModal').style.display = 'none';
        var playerId = parseInt(document.body.getAttribute('data-player-id'));
        if (!playerId) { showUnsoldToast('Error: Player ID not found', true); return; }
        fetch('/web/dataset/call_kw', {
          method: 'POST',
          headers: {'Content-Type': 'application/json'},
          body: JSON.stringify({
            jsonrpc: '2.0', method: 'call',
            params: {
              model: 'auction.team.player', method: 'action_unsold',
              args: [[playerId]], kwargs: {}
            }
          })
        })
        .then(function(r) { return r.json(); })
        .then(function(result) {
          if (result.error) { showUnsoldToast('Failed to mark player as unsold', true); return; }
          var secs = (result.result && result.result.display_seconds > 0)
                     ? result.result.display_seconds : 5;
          showUnsoldStamp(secs, UNSOLD_COLOR, UNSOLD_TEXT);
        })
        .catch(function() { showUnsoldToast('Failed to mark player as unsold', true); });
      });
    }

    /* ── Toast ──────────────────────────────────────────────────────── */
    window.showUnsoldToast = function(msg, isError) {
      var t = document.getElementById('unsoldToast');
      if (!t) return;
      t.textContent = msg;
      t.style.background = isError ? '#c0392b' : '#27ae60';
      t.style.display = 'block';
      setTimeout(function() { t.style.display = 'none'; }, 3500);
    };

    /* ── UNSOLD stamp ───────────────────────────────────────────────── */
    window.showUnsoldStamp = function(displaySeconds, stampColor, stampTextColor) {
      if (!document.getElementById('_unsoldStampCSS')) {
        var s = document.createElement('style');
        s.id = '_unsoldStampCSS';
        s.textContent = '@keyframes _unsoldDrop{0%{transform:rotate(-22deg) scale(2.4);opacity:0}100%{transform:rotate(-22deg) scale(1);opacity:.92}}@keyframes _unsoldFadeIn{from{opacity:0}to{opacity:1}}';
        document.head.appendChild(s);
      }
      var img = document.getElementById('loadImage');
      if (!img) return;
      var r = img.getBoundingClientRect();
      var ov = document.createElement('div');
      ov.style.cssText = 'position:fixed;z-index:9500;top:'+r.top+'px;left:'+r.left+'px;width:'+r.width+'px;height:'+r.height+'px;background:rgba(0,0,0,0.48);display:flex;align-items:center;justify-content:center;animation:_unsoldFadeIn .35s ease;pointer-events:none;';
      var stamp = document.createElement('div');
      stamp.style.cssText = 'background:'+stampColor+';color:'+stampTextColor+';font-size:clamp(1.8rem,5vw,3.2rem);font-weight:900;letter-spacing:6px;padding:8px 36px;border:5px solid rgba(255,255,255,0.85);border-radius:6px;box-shadow:0 0 0 3px '+stampColor+',0 8px 40px rgba(0,0,0,.5);opacity:0;animation:_unsoldDrop .5s cubic-bezier(.34,1.3,.64,1) .15s forwards;text-shadow:2px 3px 8px rgba(0,0,0,.4);';
      stamp.textContent = 'UNSOLD';
      var barWrap = document.createElement('div');
      barWrap.style.cssText = 'position:absolute;bottom:12px;left:16px;right:16px;';
      var barTrack = document.createElement('div');
      barTrack.style.cssText = 'background:rgba(255,255,255,0.25);border-radius:4px;height:6px;overflow:hidden;';
      var bar = document.createElement('div');
      bar.style.cssText = 'height:100%;width:100%;background:'+stampColor+';border-radius:4px;transition:width '+displaySeconds+'s linear;';
      barTrack.appendChild(bar);
      barWrap.appendChild(barTrack);
      ov.appendChild(stamp);
      ov.appendChild(barWrap);
      document.body.appendChild(ov);
      requestAnimationFrame(function() { requestAnimationFrame(function() { bar.style.width = '0%'; }); });
      setTimeout(function() { if (ov.parentNode) ov.parentNode.removeChild(ov); changeImage(); }, displaySeconds * 1000);
    };

    /* ── Bid Summary drawer ─────────────────────────────────────────── */
    window.openBidSummary = function() {
      document.getElementById('bidSummaryFrame').src = '/auction/show/team/balance';
      document.getElementById('bidSummaryDrawer').style.right = '0';
      document.getElementById('bidSummaryTabArrow').innerHTML = '&#x2192;';
      document.getElementById('bidSummaryOverlay').style.display = 'block';
      document.body.style.overflow = 'hidden';
    };
    window.closeBidSummary = function() {
      document.getElementById('bidSummaryDrawer').style.right = '-820px';
      document.getElementById('bidSummaryTabArrow').innerHTML = '&#x2190;';
      document.getElementById('bidSummaryOverlay').style.display = 'none';
      document.body.style.overflow = '';
    };
    window.toggleBidSummary = function() {
      var r = document.getElementById('bidSummaryDrawer').style.right;
      if (r === '0px' || r === '0') { closeBidSummary(); } else { openBidSummary(); }
    };

  })();
  //
